using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // EF9: discriminator property renamed from "Discriminator" to "$type"
            b.HasDiscriminator<string>("Discriminator");
            // EF9: id no longer includes discriminator (was "Blog|1", now just "1")
            b.HasDiscriminatorInJsonId();
            // EF9: key property maps directly to JSON id instead of shadow property
            b.HasShadowId();
        });
        // Removed: HasIndex throws on Cosmos in EF9 (Cosmos indexes all properties by default)
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

